const body = $input.item.json.body || $input.item.json;
const booking = body.booking || {};
const table = body.table || {};
const payment = body.payment || {};

const amount = payment.amount
  ? Number(payment.amount).toLocaleString('vi-VN') + ' ' + (payment.currency || 'VND')
  : 'N/A';

const lines = [
  '[THONG BAO DAT BAN]',
  'Su kien: ' + (body.event || 'booking.event'),
  'Ma booking: ' + (booking.code || 'N/A'),
  'Khach: ' + (booking.guest_name || 'N/A') + ' - ' + (booking.guest_phone || 'N/A'),
  'Thoi gian: ' + (booking.booking_date || 'N/A') + ' ' + (booking.booking_time || ''),
  'So khach: ' + (booking.party_size || 'N/A'),
  'Ban so: ' + (table.id || 'N/A') + ' - Tang ' + (table.floor || 'N/A'),
  'Trang thai: ' + (booking.status_label || booking.status || 'N/A'),
  'Thanh toan: ' + (payment.status_label || payment.status || 'N/A') + ' - ' + amount,
];

if (booking.notes) {
  lines.push('Ghi chu: ' + booking.notes);
}

return { json: { text: lines.join('\n') } };
